const b = $('Webhook · Ecom Sync').first().json.body;
const clientId     = b.client_id;
const syncType     = b.sync_type || 'products'; // 'products' or 'orders'
const gsheetUrl    = b.gsheet_url || '';
const tableId      = b.table_id || '';
const columnMap    = (b.column_map && typeof b.column_map === 'object') ? b.column_map : {};

const match = gsheetUrl.match(/\/spreadsheets\/d\/([a-zA-Z0-9-_]+)/);
if (!match) throw new Error('Invalid Google Sheet URL');
const spreadsheetId = match[1];
// Default to the first tab (gid=0) when the URL doesn't name one — far more
// forgiving than requiring an exact sheet-tab name match.
const gidMatch = gsheetUrl.match(/gid=(\d+)/);
const gid = gidMatch ? gidMatch[1] : '0';

return [{ json: { clientId, syncType, spreadsheetId, gid, gsheetUrl, tableId, columnMap } }];

const meta = $('Code · Parse Request').first().json;
const raw = $input.first().json;
const csvText = typeof raw === 'string' ? raw : (raw.data ?? raw.body ?? raw.text ?? '');

// A sheet that isn't publicly viewable returns Google's HTML login/error page
// instead of CSV — bail out cleanly rather than trying to parse markup as data.
if (!csvText || /^\s*<(!doctype|html)/i.test(csvText.trim())) return [];

function parseCSV(text) {
  const rows = [];
  let row = [], field = '', inQuotes = false;
  for (let i = 0; i < text.length; i++) {
    const c = text[i];
    if (inQuotes) {
      if (c === '"') { if (text[i + 1] === '"') { field += '"'; i++; } else { inQuotes = false; } }
      else field += c;
    } else {
      if (c === '"') inQuotes = true;
      else if (c === ',') { row.push(field); field = ''; }
      else if (c === '\r') { /* skip */ }
      else if (c === '\n') { row.push(field); rows.push(row); row = []; field = ''; }
      else field += c;
    }
  }
  if (field.length || row.length) { row.push(field); rows.push(row); }
  return rows;
}

const rows = parseCSV(csvText);
if (rows.length < 2) return [];

const rawHeaders = rows[0];
const normHeaders = rawHeaders.map(h => String(h).toLowerCase().replace(/\s+/g,'_'));
const dataRows = rows.slice(1).filter(r => r.some(v => String(v).trim() !== ''));

const FIELDS_BY_TYPE = {
  products: ['name','sku','category','color','size','price','currency','stock','status','description','image_url'],
  orders: ['order_id','customer_name','customer_phone','order_date','items','total','currency','status','delivery_address','notes']
};
const targetFields = FIELDS_BY_TYPE[meta.syncType] || FIELDS_BY_TYPE.products;
const columnMap = meta.columnMap || {};

function findIndex(headerName) {
  if (!headerName) return -1;
  const needle = String(headerName).trim().toLowerCase();
  return rawHeaders.findIndex(h => String(h).trim().toLowerCase() === needle);
}

// Resolve each target field to a column index: explicit mapping first, else
// fall back to matching the normalized (snake_case) header name directly.
const fieldIndex = {};
targetFields.forEach(f => {
  const mapped = columnMap[f];
  let idx = mapped ? findIndex(mapped) : -1;
  if (idx === -1) idx = normHeaders.indexOf(f);
  fieldIndex[f] = idx;
});

const records = dataRows.map(row => {
  const obj = { client_id: meta.clientId };
  targetFields.forEach(f => {
    const idx = fieldIndex[f];
    obj[f] = idx >= 0 ? (row[idx] || '') : '';
  });
  return { json: obj };
});

return [{ json: { ...meta, records, headers: rawHeaders } }];

const { records, clientId, tableId } = $input.first().json;
// Return one item per record for bulk upsert
return records.map(r => ({ json: r }));
